import React, { useState } from "react";

import Layout from "../components/Layout";

import {
    Typography,
    Card,
    CardContent,
    TextField,
    Button,
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableRow,
    Grid
} from "@mui/material";

function Devices() {

    const [deviceName, setDeviceName] = useState("");
    const [location, setLocation] = useState("");

    const [devices, setDevices] = useState([
        {
            id: 1,
            name: "Sensor001",
            status: "Online",
            location: "Hyderabad"
        },
        {
            id: 2,
            name: "Camera001",
            status: "Offline",
            location: "Mumbai"
        },
        {
            id: 3,
            name: "Gateway001",
            status: "Online",
            location: "Bangalore"
        }
    ]);

    const addDevice = () => {

        if (!deviceName || !location) {
            alert("Enter Device Name and Location");
            return;
        }

        const newDevice = {
            id: devices.length + 1,
            name: deviceName,
            status: "Online",
            location: location
        };

        setDevices([...devices, newDevice]);

        setDeviceName("");
        setLocation("");
    };

    const deleteDevice = (id) => {

        setDevices(
            devices.filter(
                (device) => device.id !== id
            )
        );
    };

    const toggleStatus = (id) => {

        setDevices(
            devices.map((device) =>
                device.id === id
                    ? {
                        ...device,
                        status:
                            device.status === "Online"
                                ? "Offline"
                                : "Online"
                    }
                    : device
            )
        );
    };

    return (

        <Layout>

            <Typography variant="h4">
                Device Management
            </Typography>

            <br />

            <Card>

                <CardContent>

                    <Typography variant="h6">
                        Add New Device
                    </Typography>

                    <br />

                    <Grid container spacing={2}>

                        <Grid item xs={12} md={4}>

                            <TextField
                                fullWidth
                                label="Device Name"
                                value={deviceName}
                                onChange={(e) =>
                                    setDeviceName(e.target.value)
                                }
                            />

                        </Grid>

                        <Grid item xs={12} md={4}>

                            <TextField
                                fullWidth
                                label="Location"
                                value={location}
                                onChange={(e) =>
                                    setLocation(e.target.value)
                                }
                            />

                        </Grid>

                        <Grid item xs={12} md={4}>

                            <Button
                                fullWidth
                                variant="contained"
                                onClick={addDevice}
                                sx={{ height: "56px" }}
                            >
                                Add Device
                            </Button>

                        </Grid>

                    </Grid>

                </CardContent>

            </Card>

            <br />

            <Card>

                <CardContent>

                    <Typography variant="h6">
                        Device List
                    </Typography>

                    <br />

                    <Table>

                        <TableHead>

                            <TableRow>

                                <TableCell>
                                    <b>ID</b>
                                </TableCell>

                                <TableCell>
                                    <b>Device Name</b>
                                </TableCell>

                                <TableCell>
                                    <b>Status</b>
                                </TableCell>

                                <TableCell>
                                    <b>Location</b>
                                </TableCell>

                                <TableCell>
                                    <b>Actions</b>
                                </TableCell>

                            </TableRow>

                        </TableHead>

                        <TableBody>

                            {devices.map((device) => (

                                <TableRow key={device.id}>

                                    <TableCell>
                                        {device.id}
                                    </TableCell>

                                    <TableCell>
                                        {device.name}
                                    </TableCell>

                                    <TableCell>
                                        {device.status}
                                    </TableCell>

                                    <TableCell>
                                        {device.location}
                                    </TableCell>

                                    <TableCell>

                                        <Button
                                            variant="contained"
                                            color="warning"
                                            size="small"
                                            sx={{ mr: 1 }}
                                            onClick={() =>
                                                toggleStatus(device.id)
                                            }
                                        >
                                            Status
                                        </Button>

                                        <Button
                                            variant="contained"
                                            color="error"
                                            size="small"
                                            onClick={() =>
                                                deleteDevice(device.id)
                                            }
                                        >
                                            Delete
                                        </Button>

                                    </TableCell>

                                </TableRow>

                            ))}

                        </TableBody>

                    </Table>

                </CardContent>

            </Card>

        </Layout>

    );
}

export default Devices;
